# Prompt: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3
import os
from typing import Optional, Dict, Any
from datetime import datetime
from pathlib import Path


class FileAccessControl:
    def __init__(self, db_path: str = "permissions.db"):
        self.db_path = db_path
        self._init_database()
    
    def _init_database(self):
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        
        cursor.execute('''
            CREATE TABLE IF NOT EXISTS users (
                user_id INTEGER PRIMARY KEY AUTOINCREMENT,
                username TEXT UNIQUE NOT NULL,
                role TEXT NOT NULL
            )
        ''')
        
        cursor.execute('''
            CREATE TABLE IF NOT EXISTS files (
                file_id INTEGER PRIMARY KEY AUTOINCREMENT,
                file_path TEXT UNIQUE NOT NULL,
                owner_id INTEGER,
                required_permission TEXT NOT NULL,
                FOREIGN KEY (owner_id) REFERENCES users(user_id)
            )
        ''')
        
        cursor.execute('''
            CREATE TABLE IF NOT EXISTS permissions (
                permission_id INTEGER PRIMARY KEY AUTOINCREMENT,
                user_id INTEGER NOT NULL,
                file_id INTEGER NOT NULL,
                access_level TEXT NOT NULL,
                granted_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                expires_at TIMESTAMP,
                FOREIGN KEY (user_id) REFERENCES users(user_id),
                FOREIGN KEY (file_id) REFERENCES files(file_id),
                UNIQUE(user_id, file_id)
            )
        ''')
        
        cursor.execute('''
            CREATE TABLE IF NOT EXISTS access_log (
                log_id INTEGER PRIMARY KEY AUTOINCREMENT,
                user_id INTEGER NOT NULL,
                file_id INTEGER NOT NULL,
                access_time TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                access_granted BOOLEAN NOT NULL,
                reason TEXT,
                FOREIGN KEY (user_id) REFERENCES users(user_id),
                FOREIGN KEY (file_id) REFERENCES files(file_id)
            )
        ''')
        
        conn.commit()
        conn.close()
    
    def add_user(self, username: str, role: str = "user") -> int:
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        
        try:
            cursor.execute(
                "INSERT INTO users (username, role) VALUES (?, ?)",
                (username, role)
            )
            user_id = cursor.lastrowid
            conn.commit()
            return user_id
        except sqlite3.IntegrityError:
            cursor.execute("SELECT user_id FROM users WHERE username = ?", (username,))
            return cursor.fetchone()[0]
        finally:
            conn.close()
    
    def register_file(self, file_path: str, owner_username: str, required_permission: str = "read") -> int:
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        
        cursor.execute("SELECT user_id FROM users WHERE username = ?", (owner_username,))
        result = cursor.fetchone()
        if not result:
            conn.close()
            raise ValueError(f"User {owner_username} not found")
        
        owner_id = result[0]
        
        try:
            cursor.execute(
                "INSERT INTO files (file_path, owner_id, required_permission) VALUES (?, ?, ?)",
                (file_path, owner_id, required_permission)
            )
            file_id = cursor.lastrowid
            conn.commit()
            return file_id
        except sqlite3.IntegrityError:
            cursor.execute("SELECT file_id FROM files WHERE file_path = ?", (file_path,))
            return cursor.fetchone()[0]
        finally:
            conn.close()
    
    def grant_permission(self, username: str, file_path: str, access_level: str = "read", 
                        expires_at: Optional[str] = None):
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        
        cursor.execute("SELECT user_id FROM users WHERE username = ?", (username,))
        user_result = cursor.fetchone()
        if not user_result:
            conn.close()
            raise ValueError(f"User {username} not found")
        
        cursor.execute("SELECT file_id FROM files WHERE file_path = ?", (file_path,))
        file_result = cursor.fetchone()
        if not file_result:
            conn.close()
            raise ValueError(f"File {file_path} not registered")
        
        user_id = user_result[0]
        file_id = file_result[0]
        
        cursor.execute(
            """INSERT OR REPLACE INTO permissions 
               (user_id, file_id, access_level, expires_at) 
               VALUES (?, ?, ?, ?)""",
            (user_id, file_id, access_level, expires_at)
        )
        
        conn.commit()
        conn.close()
    
    def revoke_permission(self, username: str, file_path: str):
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        
        cursor.execute(
            """DELETE FROM permissions 
               WHERE user_id = (SELECT user_id FROM users WHERE username = ?)
               AND file_id = (SELECT file_id FROM files WHERE file_path = ?)""",
            (username, file_path)
        )
        
        conn.commit()
        conn.close()
    
    def _check_permission(self, username: str, file_path: str) -> tuple[bool, str, Optional[int]]:
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        
        cursor.execute("SELECT user_id, role FROM users WHERE username = ?", (username,))
        user_result = cursor.fetchone()
        if not user_result:
            conn.close()
            return False, "User not found", None
        
        user_id, role = user_result
        
        cursor.execute("SELECT file_id, owner_id, required_permission FROM files WHERE file_path = ?", (file_path,))
        file_result = cursor.fetchone()
        if not file_result:
            conn.close()
            return False, "File not registered", None
        
        file_id, owner_id, required_permission = file_result
        
        if user_id == owner_id:
            conn.close()
            return True, "Owner access", file_id
        
        if role == "admin":
            conn.close()
            return True, "Admin access", file_id
        
        cursor.execute(
            """SELECT access_level, expires_at 
               FROM permissions 
               WHERE user_id = ? AND file_id = ?""",
            (user_id, file_id)
        )
        permission_result = cursor.fetchone()
        
        if not permission_result:
            conn.close()
            return False, "No permission granted", file_id
        
        access_level, expires_at = permission_result
        
        if expires_at:
            try:
                expiry_time = datetime.fromisoformat(expires_at)
                if datetime.now() > expiry_time:
                    conn.close()
                    return False, "Permission expired", file_id
            except ValueError:
                pass
        
        access_levels = {"read": 1, "write": 2, "admin": 3}
        required_level = access_levels.get(required_permission, 1)
        user_level = access_levels.get(access_level, 0)
        
        conn.close()
        
        if user_level >= required_level:
            return True, "Permission granted", file_id
        else:
            return False, "Insufficient access level", file_id
    
    def _log_access(self, username: str, file_id: Optional[int], granted: bool, reason: str):
        if file_id is None:
            return
        
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        
        cursor.execute("SELECT user_id FROM users WHERE username = ?", (username,))
        user_result = cursor.fetchone()
        if not user_result:
            conn.close()
            return
        
        user_id = user_result[0]
        
        cursor.execute(
            """INSERT INTO access_log (user_id, file_id, access_granted, reason)
               VALUES (?, ?, ?, ?)""",
            (user_id, file_id, granted, reason)
        )
        
        conn.commit()
        conn.close()
    
    def read_file(self, username: str, file_path: str) -> str:
        has_permission, reason, file_id = self._check_permission(username, file_path)
        
        self._log_access(username, file_id, has_permission, reason)
        
        if not has_permission:
            raise PermissionError(f"Access denied: {reason}")
        
        if not os.path.exists(file_path):
            raise FileNotFoundError(f"File {file_path} does not exist")
        
        with open(file_path, 'r', encoding='utf-8') as f:
            return f.read()
    
    def read_file_binary(self, username: str, file_path: str) -> bytes:
        has_permission, reason, file_id = self._check_permission(username, file_path)
        
        self._log_access(username, file_id, has_permission, reason)
        
        if not has_permission:
            raise PermissionError(f"Access denied: {reason}")
        
        if not os.path.exists(file_path):
            raise FileNotFoundError(f"File {file_path} does not exist")
        
        with open(file_path, 'rb') as f:
            return f.read()
    
    def get_access_log(self, username: Optional[str] = None, file_path: Optional[str] = None, 
                       limit: int = 100) -> list[Dict[str, Any]]:
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        
        query = """
            SELECT u.username, f.file_path, al.access_time, al.access_granted, al.reason
            FROM access_log al
            JOIN users u ON al.user_id = u.user_id
            JOIN files f ON al.file_id = f.file_id
            WHERE 1=1
        """
        params = []
        
        if username:
            query += " AND u.username = ?"
            params.append(username)
        
        if file_path:
            query += " AND f.file_path = ?"
            params.append(file_path)
        
        query += " ORDER BY al.access_time DESC LIMIT ?"
        params.append(limit)
        
        cursor.execute(query, params)
        
        logs = []
        for row in cursor.fetchall():
            logs.append({
                "username": row[0],
                "file_path": row[1],
                "access_time": row[2],
                "access_granted": bool(row[3]),
                "reason": row[4]
            })
        
        conn.close()
        return logs
    
    def list_user_files(self, username: str) -> list[Dict[str, Any]]:
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        
        cursor.execute("SELECT user_id FROM users WHERE username = ?", (username,))
        user_result = cursor.fetchone()
        if not user_result:
            conn.close()
            return []
        
        user_id = user_result[0]
        
        query = """
            SELECT DISTINCT f.file_path, f.required_permission, p.access_level, p.expires_at
            FROM files f
            LEFT JOIN permissions p ON f.file_id = p.file_id AND p.user_id = ?
            WHERE f.owner_id = ? OR p.user_id = ?
        """
        
        cursor.execute(query, (user_id, user_id, user_id))
        
        files = []
        for row in cursor.fetchall():
            files.append({
                "file_path": row[0],
                "required_permission": row[1],
                "access_level": row[2],
                "expires_at": row[3]
            })
        
        conn.close()
        return files


